import{_ as i,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"平台功能: 模型与配额 | opencode-antigravity-auth","description":"了解 Antigravity Auth 的模型类型和双配额系统。掌握模型选择、Thinking 配置和 Google Search 方法，优化配额使用。","frontmatter":{"title":"平台功能: 模型与配额 | opencode-antigravity-auth","sidebarTitle":"解锁双配额系统","subtitle":"平台功能: 模型与配额","description":"了解 Antigravity Auth 的模型类型和双配额系统。掌握模型选择、Thinking 配置和 Google Search 方法，优化配额使用。","order":2},"headers":[],"relativePath":"zh/NoeFabris/opencode-antigravity-auth/platforms/index.md","filePath":"zh/NoeFabris/opencode-antigravity-auth/platforms/index.md"}'),n={name:"zh/NoeFabris/opencode-antigravity-auth/platforms/index.md"};function o(r,a,h,d,s,u){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="平台功能" tabindex="-1">平台功能 <a class="header-anchor" href="#平台功能" aria-label="Permalink to &quot;平台功能&quot;">​</a></h1><p>本章节帮助你深入了解 Antigravity Auth 插件支持的模型、配额系统和平台特性。你将学会选择合适的模型、配置 Thinking 能力、启用 Google Search 以及最大化配额利用率。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">开始前请确认</p><p>在学习本章节之前，请确保你已完成：</p><ul><li><a href="./../start/quick-install/">快速安装</a>：完成插件安装和首次认证</li><li><a href="./../start/first-request/">首次请求</a>：成功发起第一个模型请求</li></ul></div><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><p>按以下顺序学习，循序渐进掌握平台功能：</p><h3 id="_1-可用模型" tabindex="-1">1. <a href="./available-models/">可用模型</a> <a class="header-anchor" href="#_1-可用模型" aria-label="Permalink to &quot;1. [可用模型](./available-models/)&quot;">​</a></h3><p>了解所有可用的模型及其变体配置</p><ul><li>认识 Claude Opus 4.5、Sonnet 4.5 和 Gemini 3 Pro/Flash</li><li>理解 Antigravity 和 Gemini CLI 两个配额池的模型分布</li><li>掌握 <code>--variant</code> 参数的使用方法</li></ul><h3 id="_2-双配额系统" tabindex="-1">2. <a href="./dual-quota-system/">双配额系统</a> <a class="header-anchor" href="#_2-双配额系统" aria-label="Permalink to &quot;2. [双配额系统](./dual-quota-system/)&quot;">​</a></h3><p>理解 Antigravity 和 Gemini CLI 双配额池的工作原理</p><ul><li>了解每个账户如何拥有两个独立的 Gemini 配额池</li><li>启用自动 fallback 配置，实现配额翻倍</li><li>显式指定模型使用特定配额池</li></ul><h3 id="_3-google-search-grounding" tabindex="-1">3. <a href="./google-search-grounding/">Google Search Grounding</a> <a class="header-anchor" href="#_3-google-search-grounding" aria-label="Permalink to &quot;3. [Google Search Grounding](./google-search-grounding/)&quot;">​</a></h3><p>为 Gemini 模型启用 Google Search，提升事实准确性</p><ul><li>让 Gemini 能够搜索实时网络信息</li><li>调节搜索阈值，控制搜索频率</li><li>根据任务需求选择合适的配置</li></ul><h3 id="_4-thinking-模型" tabindex="-1">4. <a href="./thinking-models/">Thinking 模型</a> <a class="header-anchor" href="#_4-thinking-模型" aria-label="Permalink to &quot;4. [Thinking 模型](./thinking-models/)&quot;">​</a></h3><p>掌握 Claude 和 Gemini 3 Thinking 模型的配置和使用</p><ul><li>配置 Claude 的 thinking budget</li><li>使用 Gemini 3 的 thinking level（minimal/low/medium/high）</li><li>理解 interleaved thinking 和思考块保留策略</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章节后，你可以继续学习：</p><ul><li><a href="./../advanced/multi-account-setup/">多账户配置</a>：配置多个 Google 账户，实现配额池化和负载均衡</li><li><a href="./../advanced/account-selection-strategies/">账户选择策略</a>：掌握 sticky、round-robin、hybrid 三种策略的最佳实践</li><li><a href="./../advanced/configuration-guide/">配置指南</a>：掌握所有配置选项，按需定制插件行为</li></ul>',21)])])}const m=i(n,[["render",o]]);export{g as __pageData,m as default};
